  import { jest } from '@jest/globals'
  import { calculateNextRetryAt, processWebhookEvent,
           WebhookRetryWorker } from '../../src/workers/webhook-retry'
  import { WebhookStatus } from '../../src/types/webhook'
  import { inMemoryWebhookStore } from '../../src/db/webhook-events'

  // Mock fetch for HTTP delivery
  const mockFetch = jest.fn()
  global.fetch = mockFetch

  beforeEach(() => {
    mockFetch.mockReset()
    inMemoryWebhookStore.clear()
    jest.useFakeTimers()
  })

  afterEach(() => {
    jest.useRealTimers()
  })

  describe('calculateNextRetryAt', () => {
    it('attempt 1: retries after 1s', () => {
      const now = new Date('2026-05-27T10:00:00Z')
      const next = calculateNextRetryAt(1, now)
      const diffMs = next.getTime() - now.getTime()
      expect(diffMs).toBeGreaterThanOrEqual(950)   // 1s - 5% jitter
      expect(diffMs).toBeLessThanOrEqual(1050)     // 1s + 5% jitter
    })
    it('attempt 2: retries after ~2s', () => { /* same pattern */ })
    it('attempt 3: retries after ~4s', () => { /* same pattern */ })
    it('attempt 4: retries after ~8s', () => { /* same pattern */ })
    it('attempt 5: capped at 30s total', () => {
      const now = new Date('2026-05-27T10:00:00Z')
      // attempt 5 base = 16s, but total (1+2+4+8+16=31s) exceeds 30s cap
      // so attempt 5 should be capped: next_retry = now + (30 - 15) = now + 15s
      const next = calculateNextRetryAt(5, now)
      const diffSecs = (next.getTime() - now.getTime()) / 1000
      expect(diffSecs).toBeGreaterThanOrEqual(14.25)  // 15s - 5% jitter
      expect(diffSecs).toBeLessThanOrEqual(15.75)     // 15s + 5% jitter
    })
  })

  describe('HTTP response handling', () => {
    it('does NOT retry on 400 (permanent failure)', async () => {
      mockFetch.mockResolvedValue({ ok: false, status: 400 })
      const event = createTestEvent()
      await processWebhookEvent(event)
      const updated = inMemoryWebhookStore.get(event.id)
      expect(updated!.status).toBe(WebhookStatus.Failed)
      expect(updated!.attemptCount).toBe(1)  // no retries
    })
    it('does NOT retry on 404 (permanent failure)', async () => {
      mockFetch.mockResolvedValue({ ok: false, status: 404 })
      const event = createTestEvent()
      await processWebhookEvent(event)
      expect(inMemoryWebhookStore.get(event.id)!.status).toBe(WebhookStatus.Failed)
    })
    it('DOES retry on 500 (transient failure)', async () => {
      mockFetch.mockResolvedValue({ ok: false, status: 500 })
      const event = createTestEvent()
      await processWebhookEvent(event)
      const updated = inMemoryWebhookStore.get(event.id)
      expect(updated!.status).toBe(WebhookStatus.Pending)  // still pending, retry queued
      expect(updated!.nextRetryAt).not.toBeNull()
    })
    it('DOES retry on network error (fetch throws)', async () => {
      mockFetch.mockRejectedValue(new Error('ECONNREFUSED'))
      const event = createTestEvent()
      await processWebhookEvent(event)
      expect(inMemoryWebhookStore.get(event.id)!.nextRetryAt).not.toBeNull()
    })
  })

  describe('circuit breaker', () => {
    it('marks target as Dead after 3 consecutive failures', async () => {
      mockFetch.mockResolvedValue({ ok: false, status: 500 })
      const targetUrl = 'https://dead-target.example.com/webhook'
      // Deliver 3 events to same target, all fail
      for (let i = 0; i < 3; i++) {
        const event = createTestEvent({ targetUrl })
        await processWebhookEvent(event)
      }
      const target = inMemoryWebhookStore.getTarget(targetUrl)
      expect(target!.status).toBe('dead')
      expect(target!.consecutiveFailures).toBe(3)
    })
    it('stops retrying events to a dead target', async () => {
      mockFetch.mockResolvedValue({ ok: false, status: 500 })
      const targetUrl = 'https://dead-target.example.com/webhook'
      // Mark target as dead
      inMemoryWebhookStore.setTargetDead(targetUrl)
      const event = createTestEvent({ targetUrl })
      await processWebhookEvent(event)
      // fetch should NOT have been called
      expect(mockFetch).not.toHaveBeenCalled()
      expect(inMemoryWebhookStore.get(event.id)!.status).toBe(WebhookStatus.Dead)
    })
    it('resets circuit breaker on successful delivery', async () => {
      const targetUrl = 'https://recovering-target.example.com/webhook'
      inMemoryWebhookStore.setTargetFailures(targetUrl, 2)  // 2 failures, not yet dead
      mockFetch.mockResolvedValue({ ok: true, status: 200 })
      const event = createTestEvent({ targetUrl })
      await processWebhookEvent(event)
      const target = inMemoryWebhookStore.getTarget(targetUrl)
      expect(target!.consecutiveFailures).toBe(0)  // reset on success
    })
  })

  describe('idempotency', () => {
    it('each retry attempt has a unique delivery_id', async () => {
      mockFetch.mockResolvedValue({ ok: false, status: 500 })
      const event = createTestEvent()
      // First attempt
      await processWebhookEvent(event)
      const attempt1DeliveryId = mockFetch.mock.calls[0][1]?.body?.deliveryId
      // Advance timer to trigger retry
      jest.advanceTimersByTime(1100)  // 1s + buffer
      await processWebhookEvent(event)
      const attempt2DeliveryId = mockFetch.mock.calls[1][1]?.body?.deliveryId
      expect(attempt1DeliveryId).not.toBe(attempt2DeliveryId)  // unique UUIDs
    })
  })

  describe('persistence simulation', () => {
    it('pending event survives store reload and retries', () => {
      const event = createTestEvent()
      inMemoryWebhookStore.set(event.id, {
        ...event, status: WebhookStatus.Pending,
        nextRetryAt: new Date(Date.now() - 1000),  // retry overdue
        attemptCount: 1,
      })
      // Simulate store reload by getting retryable events
      const retryable = inMemoryWebhookStore.getRetryable()
      expect(retryable).toContainEqual(expect.objectContaining({ id: event.id }))
    })
  })

  describe('retention', () => {
    it('pruneFailedEvents removes events older than 7 days', () => {
      const oldEvent = createTestEvent()
      inMemoryWebhookStore.set(oldEvent.id, {
        ...oldEvent, status: WebhookStatus.Failed,
        createdAt: new Date(Date.now() - 8 * 24 * 60 * 60 * 1000),  // 8 days old
      })
      const pruned = inMemoryWebhookStore.pruneFailedEvents(7)
      expect(pruned).toBe(1)
      expect(inMemoryWebhookStore.get(oldEvent.id)).toBeUndefined()
    })
    it('does not prune events younger than 7 days', () => {
      const recentEvent = createTestEvent()
      inMemoryWebhookStore.set(recentEvent.id, {
        ...recentEvent, status: WebhookStatus.Failed,
        createdAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000),  // 3 days old
      })
      expect(inMemoryWebhookStore.pruneFailedEvents(7)).toBe(0)
    })
  })

  function createTestEvent(overrides = {}) {
    return {
      id:            crypto.randomUUID(),
      targetUrl:     'https://test.example.com/webhook',
      payload:       { event: 'test.created', data: { id: 1 } },
      deliveryId:    crypto.randomUUID(),
      attemptCount:  0,
      lastAttemptAt: null,
      nextRetryAt:   null,
      status:        WebhookStatus.Pending,
      createdAt:     new Date(),
      ...overrides,
    }
  }
